/* USE : AuthorInExRegistMapper.deleteUserMenu */
DELETE
FROM    TB_WB_AUTHOR_USER_IN_EX
WHERE   USER_ID     =   #{userId}
AND     RESRCE_CD   =   #{resrceCd}

    AND AUTHOR_PRODC_FG = #{authorProdcFg}

